import MainLayout from "@/components/layouts/main-layout";
import { Section } from "@/components/primitives/section";

export default function Layout({ children }: { children: React.ReactNode }) {
  return (
    <>
      <MainLayout className="flex flex-col" header={false}>
        <Section className="grow min-h-screen">{children}</Section>
      </MainLayout>
    </>
  );
}

import type { Metadata } from "next";
import { AuthBranding } from "@/app/(app)/(authentication)/_components/auth-branding";
import { AuthenticationCard } from "@/app/(app)/(authentication)/_components/authentication-card";
import { SignIn } from "@/app/(app)/(authentication)/sign-in/_components/sign-in";
import { Icon } from "@/components/assets/icon";
import { constructMetadata } from "@/config/metadata";
import { siteConfig } from "@/config/site-config";
import { env } from "@/env";

export const metadata: Metadata = constructMetadata({
  title: "Sign In",
  description: `Sign in to your ${siteConfig.name} account to access your dashboard, projects, and settings.`,
});

export default function SignInPage() {
  const hasAuth = env.NEXT_PUBLIC_FEATURE_AUTH_ENABLED;

  if (!hasAuth) {
    return (
      <div className="flex w-full max-w-sm flex-col gap-6">
        <div className="flex items-center gap-2 self-center font-medium">
          <div className="flex h-6 w-6 items-center justify-center rounded-md bg-primary text-primary-foreground">
            <Icon />
          </div>
          {siteConfig.title}
        </div>
        <div className="text-center text-xs text-muted-foreground flex items-center justify-center gap-2">
          <span aria-hidden="true">&gt;</span>
          <span>Login and sign-up are not available at this time.</span>
        </div>
      </div>
    );
  }

  return (
    <div className="flex w-full max-w-sm flex-col gap-6">
      <AuthBranding />
      <AuthenticationCard>
        <SignIn />
      </AuthenticationCard>
    </div>
  );
}

import { AuthForm } from "@/app/(app)/(authentication)/_components/auth-form";
import { CredentialsForm } from "@/app/(app)/(authentication)/_components/credentials-form";
import { GuestForm } from "@/app/(app)/(authentication)/_components/guest-form";
import { Divider } from "@/components/primitives/divider";
import { env } from "@/env";
// Compute guest-only on server component via build flags

export const SignIn = () => {
  // Special handling for guest-only mode
  const isGuestOnlyMode =
    !!env.NEXT_PUBLIC_FEATURE_AUTH_GUEST_ENABLED && !env.NEXT_PUBLIC_FEATURE_AUTH_METHODS_ENABLED;
  if (isGuestOnlyMode) {
    return (
      <AuthForm
        mode="sign-in"
        withFooter={false}
        title="Welcome"
        description="Enter your name to get started"
      >
        <GuestForm />
      </AuthForm>
    );
  }

  return (
    <AuthForm mode="sign-in" withFooter={false}>
      {env.NEXT_PUBLIC_FEATURE_AUTH_CREDENTIALS_ENABLED && (
        <>
          <Divider text="Or continue with email" />
          <CredentialsForm />
        </>
      )}
    </AuthForm>
  );
};

import type { Metadata } from "next";
import { redirect } from "next/navigation";
import { AuthBranding } from "@/app/(app)/(authentication)/_components/auth-branding";
import { AuthForm } from "@/app/(app)/(authentication)/_components/auth-form";
import { AuthenticationCard } from "@/app/(app)/(authentication)/_components/authentication-card";
import { Icon } from "@/components/assets/icon";
import { Divider } from "@/components/primitives/divider";
import { constructMetadata } from "@/config/metadata";
import { routes } from "@/config/routes";
import { siteConfig } from "@/config/site-config";
import { env } from "@/env";
import { SignUpForm } from "./_components/sign-up-form";

export const metadata: Metadata = constructMetadata({
  title: "Create Account",
  description: `Create your ${siteConfig.name} account to start building and deploying your applications.`,
});

export default async function SignUpPage() {
  const hasAuth = env.NEXT_PUBLIC_FEATURE_AUTH_ENABLED;
  const isGuestOnlyMode =
    !!env.NEXT_PUBLIC_FEATURE_AUTH_GUEST_ENABLED && !env.NEXT_PUBLIC_FEATURE_AUTH_METHODS_ENABLED;

  /*
   * Redirect to sign-in page when no authentication methods are available
   * since users can create their own names through the guest form
   */
  if (isGuestOnlyMode) {
    redirect(routes.auth.signIn);
  }

  if (!hasAuth) {
    return (
      <div className="flex w-full max-w-sm flex-col gap-6">
        <div className="flex items-center gap-2 self-center font-medium">
          <div className="flex h-6 w-6 items-center justify-center rounded-md bg-primary text-primary-foreground">
            <Icon />
          </div>
          {siteConfig.title}
        </div>
        <div className="text-center text-xs text-muted-foreground flex items-center justify-center gap-2">
          <span aria-hidden="true">&gt;</span>
          <span>Login and sign-up are not available at this time.</span>
        </div>
      </div>
    );
  }

  return (
    <div className="flex w-full max-w-sm flex-col gap-6">
      <AuthBranding />
      <AuthenticationCard>
        <AuthForm mode="sign-up">
          {env.NEXT_PUBLIC_FEATURE_AUTH_CREDENTIALS_ENABLED && (
            <>
              <Divider text="Or continue with email" />
              <SignUpForm />
            </>
          )}
        </AuthForm>
      </AuthenticationCard>
    </div>
  );
}

import { AuthForm } from "@/app/(app)/(authentication)/_components/auth-form";
import { env } from "@/env";
import { SignUpForm } from "./sign-up-form";

export const SignUp = () => {
  return (
    <>
      <AuthForm mode="sign-up" title="Create an account" description="Sign up to get started">
        {env.NEXT_PUBLIC_FEATURE_AUTH_CREDENTIALS_ENABLED && <SignUpForm />}
      </AuthForm>
    </>
  );
};

"use client";

import { zodResolver } from "@hookform/resolvers/zod";
import { useRouter } from "next/navigation";
import { useSession } from "next-auth/react";
import { useForm } from "react-hook-form";
import { toast } from "sonner";
import type { z } from "zod";

import { Button } from "@/components/ui/button";
import {
  Form,
  FormControl,
  FormField,
  FormItem,
  FormLabel,
  FormMessage,
} from "@/components/ui/form";
import { Input } from "@/components/ui/input";
import { routes } from "@/config/routes";
import { signUpSchema } from "@/lib/schemas/auth";
import { getSchemaDefaults } from "@/lib/utils/get-schema-defaults";
import { signUpWithCredentialsAction } from "@/server/actions/auth";

type SignUpFormValues = z.infer<typeof signUpSchema>;

export const SignUpForm = () => {
  const router = useRouter();
  const { update: updateSession } = useSession();
  const form = useForm<SignUpFormValues>({
    resolver: zodResolver(signUpSchema),
    defaultValues: {
      ...getSchemaDefaults<typeof signUpSchema>(signUpSchema),
      redirectTo: routes.home,
      redirect: true,
    },
  });

  async function onSubmit(values: SignUpFormValues) {
    try {
      // Create FormData to match the expected function signature
      const formData = new FormData();
      formData.append("email", values.email);
      formData.append("password", values.password);
      formData.append("redirect", "false");
      formData.append("redirectTo", routes.home);

      const result = await signUpWithCredentialsAction({}, formData);

      // Check if the sign-up was okful
      if (result?.ok) {
        toast.success("Account created successfully");
        // Update the session before redirecting
        await updateSession();
        router.push(routes.home);
        router.refresh(); // Refresh to update the session
        return;
      }

      if (result?.error) {
        // Handle error from result object
        throw new Error(result.error);
      }

      // If we get here, something unexpected happened
      throw new Error("Sign up failed");
    } catch (error) {
      if (error instanceof Error) {
        if (error.message.includes("User already exists")) {
          form.setError("email", {
            type: "manual",
            message: "An account with this email already exists.",
          });
        } else {
          toast.error("Error creating account", {
            description: error.message,
          });
        }
      } else {
        toast.error("Error creating account", {
          description: "Something went wrong. Please try again.",
        });
      }
    }
  }

  return (
    <Form {...form}>
      <form onSubmit={form.handleSubmit(onSubmit)} className="grid gap-4">
        <FormField
          control={form.control}
          name="email"
          render={({ field }) => (
            <FormItem>
              <FormLabel>Email</FormLabel>
              <FormControl>
                <Input placeholder="me@example.com" type="email" autoComplete="email" {...field} />
              </FormControl>
              <FormMessage />
            </FormItem>
          )}
        />
        <FormField
          control={form.control}
          name="password"
          render={({ field }) => (
            <FormItem>
              <FormLabel>Password</FormLabel>
              <FormControl>
                <Input type="password" autoComplete="new-password" {...field} />
              </FormControl>
              <FormMessage />
            </FormItem>
          )}
        />
        <Button
          type="submit"
          className="w-full"
          disabled={form.formState.isSubmitting || !form.formState.isValid}
        >
          {form.formState.isSubmitting ? "Creating account..." : "Create account"}
        </Button>
      </form>
    </Form>
  );
};

import type { Metadata } from "next";
import { AuthBranding } from "@/app/(app)/(authentication)/_components/auth-branding";
import { ForgotPasswordForm } from "@/app/(app)/(authentication)/forgot-password/_components/forgot-password-form";
import { CardContent, CardDescription, CardHeader, CardTitle } from "@/components/ui/card";
import { constructMetadata } from "@/config/metadata";
import { siteConfig } from "@/config/site-config";
import { AuthenticationCard } from "../_components/authentication-card";

export const metadata: Metadata = constructMetadata({
  title: "Forgot Password",
  description: `Reset your ${siteConfig.name} account password. Enter your email to receive a password reset link.`,
});

export default function ForgotPasswordPage() {
  return (
    <div className="flex w-full max-w-sm flex-col gap-6">
      <AuthBranding />
      <AuthenticationCard>
        <CardHeader>
          <CardTitle className="text-2xl">Forgot Password</CardTitle>
          <CardDescription>Enter your email below to reset your password</CardDescription>
