"use client";

import { zodResolver } from "@hookform/resolvers/zod";
import { useRouter } from "next/navigation";
import { type ControllerRenderProps, useForm } from "react-hook-form";
import { toast } from "sonner";
import type { z } from "zod";
import { Button } from "@/components/ui/button";
import {
  Form,
  FormControl,
  FormField,
  FormItem,
  FormLabel,
  FormMessage,
} from "@/components/ui/form";
import { Input } from "@/components/ui/input";
import { routes } from "@/config/routes";
import { resetPasswordSchema } from "@/lib/schemas/auth";
import { getSchemaDefaults } from "@/lib/utils/get-schema-defaults";
import { resetPasswordAction } from "@/server/actions/auth";

type ResetPasswordFormValues = z.infer<typeof resetPasswordSchema>;

export function ResetPasswordForm({ token }: { token?: string }) {
  const router = useRouter();

  const form = useForm<ResetPasswordFormValues>({
    resolver: zodResolver(resetPasswordSchema),
    defaultValues: {
      ...getSchemaDefaults<typeof resetPasswordSchema>(resetPasswordSchema),
      token: token || "",
    },
  });

  async function onSubmit(values: ResetPasswordFormValues) {
    if (!values.token) {
      toast.error("Missing reset token", {
        description: "The password reset link is invalid or has expired.",
      });
      return;
    }

    try {
      const result = await resetPasswordAction(values);

      // Handle different result types
      if (Array.isArray(result)) {
        // If result is a tuple [data, error], check the first element
        const [data, error] = result;
        if (error) {
          toast.error("Error resetting password", {
            description: error.message || "The password reset link is invalid or has expired.",
          });
        } else if (
          data &&
          typeof data === "object" &&
          "ok" in data &&
          (data as { ok: boolean }).ok
        ) {
          toast.success("Password reset successful", {
            description: "You can now sign in with your new password.",
          });
          router.push(routes.auth.signIn);
        }
      } else if (result && typeof result === "object" && "ok" in result) {
        // If result is a direct object with ok property
        const typedResult = result as { ok: boolean; error?: string };
        if (typedResult.ok) {
          toast.success("Password reset successful", {
            description: "You can now sign in with your new password.",
          });
          router.push(routes.auth.signIn);
        } else {
          toast.error("Error resetting password", {
            description: typedResult.error || "The password reset link is invalid or has expired.",
          });
        }
      }
    } catch (error) {
      toast.error("Error resetting password", {
        description: "An unexpected error occurred. Please try again.",
      });
    }
  }

  // Don't show the form if no token is provided
  if (!token) {
    return (
      <div className="text-center">
        <p className="mb-4">The password reset link is invalid or has expired.</p>
        <Button onClick={() => router.push(routes.auth.forgotPassword)}>
          Request a new password reset link
        </Button>
      </div>
    );
  }

  return (
    <Form {...form}>
      <form onSubmit={form.handleSubmit(onSubmit)} className="flex flex-col gap-sm">
        <FormField
          control={form.control}
          name="password"
          render={({
            field,
          }: {
            field: ControllerRenderProps<ResetPasswordFormValues, "password">;
          }) => (
            <FormItem>
              <FormLabel>New Password</FormLabel>
              <FormControl>
                <Input type="password" placeholder="••••••••" {...field} />
              </FormControl>
              <FormMessage />
            </FormItem>
          )}
        />
        <FormField
          control={form.control}
          name="passwordConfirm"
          render={({
            field,
          }: {
            field: ControllerRenderProps<ResetPasswordFormValues, "passwordConfirm">;
          }) => (
            <FormItem>
              <FormLabel>Confirm Password</FormLabel>
              <FormControl>
                <Input type="password" placeholder="••••••••" {...field} />
              </FormControl>
              <FormMessage />
            </FormItem>
          )}
        />
        <Button className="self-end" type="submit">
          Reset Password
        </Button>
      </form>
    </Form>
  );
}

import type { Metadata } from "next";
import { Suspense } from "react";
import { constructMetadata } from "@/config/metadata";
import { siteConfig } from "@/config/site-config";
import { AuthErrorContent } from "./_components/auth-error-content";

export const metadata: Metadata = constructMetadata({
  title: "Authentication Error",
  description: `An error occurred during authentication. Please try again or contact ${siteConfig.name} support.`,
  noIndex: true,
});

export default function AuthErrorPage() {
  return (
    <Suspense>
      <AuthErrorContent />
    </Suspense>
  );
}

"use client";

import { useSearchParams } from "next/navigation";
import { Boundary } from "@/components/primitives/boundary";
import { routes } from "@/config/routes";

// NextAuth error types + custom OAuth errors
enum AuthError {
  Configuration = "Configuration",
  AccessDenied = "AccessDenied",
  Verification = "Verification",
  OAuthSignin = "OAuthSignin",
  OAuthCallback = "OAuthCallback",
  OAuthCreateAccount = "OAuthCreateAccount",
  EmailCreateAccount = "EmailCreateAccount",
  Callback = "Callback",
  OAuthAccountNotLinked = "OAuthAccountNotLinked",
  EmailSignin = "EmailSignin",
  CredentialsSignin = "CredentialsSignin",
  SessionRequired = "SessionRequired",
  Default = "Default",
}

const errorConfig: Record<AuthError, { message: string; action: string; href: string }> = {
  [AuthError.Configuration]: {
    message: "There is a problem with the server configuration. Please contact support.",
    action: "Go home",
    href: routes.home,
  },
  [AuthError.AccessDenied]: {
    message: "You do not have permission to access this resource.",
    action: "Go home",
    href: routes.home,
  },
  [AuthError.Verification]: {
    message: "The verification link has expired or has already been used.",
    action: "Request new link",
    href: routes.auth.signIn,
  },
  [AuthError.OAuthSignin]: {
    message: "Could not start the sign-in process. Please try again.",
    action: "Try again",
    href: routes.auth.signIn,
  },
  [AuthError.OAuthCallback]: {
    message: "Could not complete sign-in. The provider may be experiencing issues.",
    action: "Try again",
    href: routes.auth.signIn,
  },
  [AuthError.OAuthCreateAccount]: {
    message: "Could not create your account. Please try a different sign-in method.",
    action: "Try again",
    href: routes.auth.signIn,
  },
  [AuthError.EmailCreateAccount]: {
    message: "Could not create your account with this email.",
    action: "Try again",
    href: routes.auth.signIn,
  },
  [AuthError.Callback]: {
    message: "Something went wrong during authentication.",
    action: "Try again",
    href: routes.auth.signIn,
  },
  [AuthError.OAuthAccountNotLinked]: {
    message:
      "This email is already associated with another account. Please sign in with your original method.",
    action: "Sign in",
    href: routes.auth.signIn,
  },
  [AuthError.EmailSignin]: {
    message: "Could not send the sign-in email. Please try again.",
    action: "Try again",
    href: routes.auth.signIn,
  },
  [AuthError.CredentialsSignin]: {
    message: "Invalid email or password. Please check your credentials.",
    action: "Try again",
    href: routes.auth.signIn,
  },
  [AuthError.SessionRequired]: {
    message: "You must be signed in to access this page.",
    action: "Sign in",
    href: routes.auth.signIn,
  },
  [AuthError.Default]: {
    message: "An unexpected error occurred. Please try again.",
    action: "Try again",
    href: routes.auth.signIn,
  },
};

// Provider display names for user-friendly messages
const providerNames: Record<string, string> = {
  github: "GitHub",
  google: "Google",
  discord: "Discord",
  gitlab: "GitLab",
  twitter: "Twitter",
  bitbucket: "Bitbucket",
  credentials: "email and password",
  email: "email and password",
};

export const AuthErrorContent = () => {
  const searchParams = useSearchParams();
  const error = searchParams?.get("error") as AuthError;
  const provider = searchParams?.get("provider");

  // Get config for this error, fallback to default
  const config = errorConfig[error] || errorConfig[AuthError.Default];

  // Customize message for OAuthAccountNotLinked with provider hint
  let message = config.message;
  if (error === AuthError.OAuthAccountNotLinked && provider) {
    const providerName = providerNames[provider] || provider;
    message = `This email is already associated with an account. Please sign in with ${providerName} instead.`;
  }

  return (
    <Boundary
      title="Authentication Error"
      description={message}
      href={config.href}
      actionText={config.action}
      className="max-w-xl mx-auto"
    >
      {error && (
        <div className="text-xs text-muted-foreground mt-4">
          Error code:{" "}
          <code className="rounded-sm bg-slate-100 dark:bg-slate-800 px-1 py-0.5 text-xs">
            {error}
          </code>
        </div>
      )}
    </Boundary>
  );
};

// This will log the user out, then redirect to the sign in page

// This happens when the authentication token expires or there is an error refreshing.

import type { NextRequest, NextResponse } from "next/server";
import { z } from "zod";
// This is a Route Handler, not a Next.js page, because signOut needs to be called by a server action or Route Handler
import { routes } from "@/config/routes";
import { SEARCH_PARAM_KEYS } from "@/config/search-param-keys";
import { STATUS_CODES } from "@/config/status-codes";
import { logger } from "@/lib/logger";
import { routeRedirect } from "@/lib/utils/redirect";
import { signOut } from "@/server/auth";

const querySchema = z.object({
  [SEARCH_PARAM_KEYS.statusCode]: z
    .enum(
      Object.keys(STATUS_CODES) as [keyof typeof STATUS_CODES, ...(keyof typeof STATUS_CODES)[]]
    )
    .optional(),
  [SEARCH_PARAM_KEYS.nextUrl]: z.string().optional(),
});

export const GET = async (request: NextRequest): Promise<NextResponse> => {
  const { searchParams } = new URL(request.url);

  // Parse any parameters from the URL
  const result = querySchema.safeParse({
    [SEARCH_PARAM_KEYS.statusCode]: searchParams.get(SEARCH_PARAM_KEYS.statusCode),
    [SEARCH_PARAM_KEYS.nextUrl]: searchParams.get(SEARCH_PARAM_KEYS.nextUrl),
  });

  await signOut({ redirect: false }).catch((error: Error) => {
    logger.error(`sign-out/route.ts - Sign out error: ${error.message}`);
  });

  // If the parameters are not valid, redirect to the sign in page
  if (!result.success) {
    return routeRedirect(routes.auth.signIn, {
      code: STATUS_CODES.AUTH_REFRESH.code,
      request,
    });
  }

  const { code = STATUS_CODES.AUTH_REFRESH.code, nextUrl } = result.data;

  logger.info(`sign-out/route.ts - Signing out with code: ${code}`);

  return routeRedirect(nextUrl ?? routes.auth.signIn, {
    code,
    request,
  });
};

"use client";

import Link from "next/link";
import { useRouter } from "next/navigation";
import { type ComponentPropsWithoutRef, type ReactNode, Suspense } from "react";
import { OAuthButtons } from "@/app/(app)/(authentication)/_components/oauth-buttons";
import { useIsModal } from "@/components/primitives/modal-context";
import { SuspenseFallback } from "@/components/primitives/suspense-fallback";
import { buttonVariants } from "@/components/ui/button";
import { CardContent } from "@/components/ui/card";
import { cn } from "@/lib/utils";
import { useAuthForm } from "../_hooks/use-auth-form";
import { AuthFooter } from "./auth-footer";
import { AuthHeader } from "./auth-header";

interface AuthFormProps extends ComponentPropsWithoutRef<"div"> {
  mode: "sign-in" | "sign-up";
  children?: ReactNode;
  title?: string;
  description?: string;
  withHeader?: boolean;
  withFooter?: boolean;
}

export function AuthForm({
  mode = "sign-in",
  className,
  children,
  title,
  description,
  withHeader = true,
  withFooter = true,
  ...props
}: AuthFormProps) {
  const router = useRouter();
  const isModal = useIsModal();
  const {
    cardTitle,
    cardDescription,
    alternateLink,
    shouldShowAlternateLink,
    showAuthUnavailable,
  } = useAuthForm(mode, title, description);

  const handleAlternateLinkClick = (e: React.MouseEvent<HTMLAnchorElement>) => {
    if (isModal) {
      e.preventDefault();
      // Use replace to avoid back-loop when navigating from modal
      router.replace(alternateLink.href);
    } else {
      // Signal to the modal intercepting route to not render
      // This prevents showing a modal when navigating between auth pages
      sessionStorage.setItem("skipAuthModal", "true");
    }
  };

  return (
    <div className={cn("flex flex-col gap-6 overflow-y-auto", className)} {...props}>
      {withHeader && (
        <AuthHeader
          title={cardTitle}
          description={cardDescription}
          showAuthUnavailable={showAuthUnavailable}
        />
      )}
      <CardContent className={cn("pb-0", !withFooter && "pb-6")}>
        <div className="grid gap-6 relative">
          {showAuthUnavailable && (
            <div className="text-center text-xs text-muted-foreground flex items-center justify-center gap-2">
              <span aria-hidden="true">&gt;</span>
              <span>Login and sign-up are not available at this time.</span>
            </div>
          )}

          {!showAuthUnavailable && (
            <>
              <OAuthButtons collapsible variant="icons" />
              <Suspense fallback={<SuspenseFallback />}>{children}</Suspense>
            </>
          )}
          {shouldShowAlternateLink && !showAuthUnavailable && (
            <div className="text-center text-sm">
              {alternateLink.text}{" "}
              <Link
                href={alternateLink.href}
                className={cn(
                  buttonVariants({ variant: "link" }),
                  "underline underline-offset-4 hover:no-underline hover:text-muted-foreground px-0"
                )}
                onClick={handleAlternateLinkClick}
              >
                {alternateLink.label}
              </Link>
            </div>
          )}
        </div>
      </CardContent>
      {withFooter && <AuthFooter />}
    </div>
  );
}

