  },
  (example) => ({
    createdByIdIdx: index("createdById_idx").on(example.createdById),
    nameIndex: index("name_idx").on(example.name),
  })
);

export type NewPost = typeof posts.$inferInsert;
export type Post = typeof posts.$inferSelect;

