    : []),
  ...(availableProviderIds.includes("discord")
    ? [
        Discord({
          clientId: env.AUTH_DISCORD_ID ?? "",
          clientSecret: env.AUTH_DISCORD_SECRET ?? "",
          allowDangerousEmailAccountLinking: true,
        }),
      ]
    : []),
  ...(availableProviderIds.includes("github")
    ? [
        GitHub({
          clientId: env.AUTH_GITHUB_ID ?? "",
          clientSecret: env.AUTH_GITHUB_SECRET ?? "",
          authorization: {
            params: {
              scope: "read:user user:email repo workflow",
            },
          },
          profile(profile) {
            return {
              id: profile.id.toString(),
              name: profile.name ?? profile.login,
              email: profile.email,
              emailVerified: null,
              image: profile.avatar_url,
              githubUsername: profile.login,
            };
          },
          checks: ["state", "pkce"],
          allowDangerousEmailAccountLinking: true,
        }),
      ]
    : []),
  ...(availableProviderIds.includes("gitlab")
    ? [
        GitLab({
          clientId: env.AUTH_GITLAB_ID ?? "",
          clientSecret: env.AUTH_GITLAB_SECRET ?? "",
          allowDangerousEmailAccountLinking: true,
        }),
      ]
    : []),
  ...(availableProviderIds.includes("google")
    ? [
        Google({
          clientId: env.AUTH_GOOGLE_ID ?? "",
          clientSecret: env.AUTH_GOOGLE_SECRET ?? "",
          allowDangerousEmailAccountLinking: true,
          profile(profile) {
            return {
              ...profile,
              id: profile.sub,
              emailVerified: profile.email_verified ? new Date() : null,
              name: profile.name || profile.given_name || profile.email?.split("@")[0] || null,
            };
          },
        }),
      ]
    : []),
  ...(availableProviderIds.includes("twitter")
    ? [
        Twitter({
          clientId: env.AUTH_TWITTER_ID ?? "",
          clientSecret: env.AUTH_TWITTER_SECRET ?? "",
          allowDangerousEmailAccountLinking: true,
        }),
      ]
    : []),

  // Vercel OAuth Provider - ONLY FOR CONNECTING ACCOUNTS, NOT FOR SIGNING IN
  ...(availableProviderIds.includes("vercel")
    ? [
        {
          id: "vercel",
          name: "Vercel",
          type: "oauth" as const,
          clientId: env.VERCEL_CLIENT_ID,
          clientSecret: env.VERCEL_CLIENT_SECRET,
          authorization: {
            url: "https://vercel.com/oauth/authorize",
            params: {
              scope: "user team",
            },
          },
          token: "https://api.vercel.com/v2/oauth/access_token",
          userinfo: {
            url: "https://api.vercel.com/v2/user",
            async request({ tokens, client }: { tokens: VercelTokens; client: VercelClient }) {
              const response = await fetch("https://api.vercel.com/v2/user", {
                headers: {
                  Authorization: `Bearer ${tokens.access_token}`,
                },
              });
              const profile = await response.json();
              return profile.user;
            },
          },
          profile(profile: VercelUserProfile) {
            return {
              id: profile.id || profile.uid || "",
              name: profile.name || profile.username || "",
              email: profile.email,
              image: profile.avatar?.url || null,
              emailVerified: null,
            };
          },
          allowDangerousEmailAccountLinking: true,
        },
      ]
    : []),
].filter(Boolean) as NextAuthConfig["providers"];

// Note: The logic for generating the list of UI-displayable providers
// (including ordering and exclusion) has been moved to:
// src/config/auth-provider-details.ts
// UI components should import `enabledAuthProviders` from there.

import { env } from "@/env";

// Define details for all possible providers in the desired UI display order.
// This list determines the base order.
const allProviderDetails = [
  // Primary OAuth
  { id: "google", name: "Google" }, // Requires FEATURE_AUTH_GOOGLE_ENABLED
  { id: "twitter", name: "Twitter" }, // Requires FEATURE_AUTH_TWITTER_ENABLED
  { id: "discord", name: "Discord" }, // Requires FEATURE_AUTH_DISCORD_ENABLED
  { id: "github", name: "GitHub" }, // Requires FEATURE_AUTH_GITHUB_ENABLED
  { id: "gitlab", name: "GitLab" }, // Requires FEATURE_AUTH_GITLAB_ENABLED
  { id: "bitbucket", name: "Bitbucket" }, // Requires FEATURE_AUTH_BITBUCKET_ENABLED
  // Other Auth Methods
  { id: "credentials", name: "Credentials" }, // Requires FEATURE_AUTH_CREDENTIALS_ENABLED
  { id: "resend", name: "Resend" }, // Requires FEATURE_AUTH_RESEND_ENABLED
  // Account Linking Only
  { id: "vercel", name: "Vercel" }, // Requires FEATURE_AUTH_VERCEL_ENABLED
  // Guest Access
  { id: "guest", name: "Guest" }, // Fallback when no auth methods are enabled
];

// Helper type for feature flag keys
type FeatureFlagKey = Extract<keyof typeof env, `NEXT_PUBLIC_FEATURE_AUTH_${string}_ENABLED`>;

// Helper object to map feature flag names to provider IDs
const flagToProviderId: Partial<Record<FeatureFlagKey, string>> = {
  NEXT_PUBLIC_FEATURE_AUTH_GOOGLE_ENABLED: "google",
  NEXT_PUBLIC_FEATURE_AUTH_TWITTER_ENABLED: "twitter",
  NEXT_PUBLIC_FEATURE_AUTH_DISCORD_ENABLED: "discord",
  NEXT_PUBLIC_FEATURE_AUTH_GITHUB_ENABLED: "github",
  NEXT_PUBLIC_FEATURE_AUTH_GITLAB_ENABLED: "gitlab",
  NEXT_PUBLIC_FEATURE_AUTH_BITBUCKET_ENABLED: "bitbucket",
  NEXT_PUBLIC_FEATURE_AUTH_CREDENTIALS_ENABLED: "credentials",
  NEXT_PUBLIC_FEATURE_AUTH_RESEND_ENABLED: "resend",
  NEXT_PUBLIC_FEATURE_AUTH_VERCEL_ENABLED: "vercel",
};

// Filter the details based on enabled features, preserving the order from allProviderDetails
const enabledProviders = allProviderDetails.filter((provider) => {
  // Guest provider is controlled by its own explicit flag
  if (provider.id === "guest") {
    return env.NEXT_PUBLIC_FEATURE_AUTH_GUEST_ENABLED;
  }

  // Find the flag corresponding to this provider ID
  const flagName = Object.keys(flagToProviderId).find(
    (key) => flagToProviderId[key as FeatureFlagKey] === provider.id
  ) as FeatureFlagKey | undefined;

  // If a flag exists for this provider, check if it's enabled in the env
  return flagName ? !!env[flagName] : false;
});

// Check if any authentication methods are enabled (excluding vercel which is for account linking only)
export const hasAuthMethods = enabledProviders.some((p) => p.id !== "vercel" && p.id !== "guest");

// Available providers reflect explicit flags only
export const availableProviderDetails = enabledProviders;

// Export just the IDs of available providers for use in server/auth.providers.ts
export const availableProviderIds = availableProviderDetails.map((p) => p.id);

// --- Constants for UI ---

// Prevent these specific providers from being shown as sign-in buttons in the UI
// They might still be enabled for other purposes (e.g., magic link, account linking)
// Clerk is excluded because it provides its own UI components
export const EXCLUDED_PROVIDERS_UI = ["clerk", "credentials", "resend", "vercel", "guest"];

// --- Generate the list for UI display ---

// Create the final list for UI components (buttons, etc.)
// This list respects the defined order and marks excluded providers.
export const enabledAuthProviders = availableProviderDetails.map((provider) => {
  // Add the exclusion flag for UI purposes
  const isExcluded = EXCLUDED_PROVIDERS_UI.includes(provider.id);
  return { ...provider, isExcluded };
}) as {
  id: string;
  name: string;
  isExcluded: boolean;
}[];

// Helper to check if only guest authentication is available
// Requires explicit guest flag AND no other authentication methods
export const isGuestOnlyMode = env.NEXT_PUBLIC_FEATURE_AUTH_GUEST_ENABLED && !hasAuthMethods;

"use server";

import { z } from "zod";
import { createServerAction } from "zsa";
import { BASE_URL } from "@/config/base-url";
import { RESEND_FROM_EMAIL } from "@/config/constants";
import { STATUS_CODES } from "@/config/status-codes";
import { env } from "@/env";
import { resend } from "@/lib/resend";
import { forgotPasswordSchema, resetPasswordSchema, signInActionSchema } from "@/lib/schemas/auth";
import type { ActionState } from "@/lib/utils/validated-action";
import { AuthService } from "@/server/services/auth-service";
import type { UserRole } from "@/types/user";

export interface AuthOptions {
  redirectTo?: string;
  redirect?: boolean;
  protect?: boolean;
  role?: UserRole;
  nextUrl?: string;
  errorCode?: string;
  email?: string;
}

export const signInWithOAuthAction = async ({
  providerId,
  options,
}: {
  providerId: string;
  options?: AuthOptions;
}) => {
  return await AuthService.signInWithOAuth(providerId, options);
};

export const signInAction = createServerAction()
  .input(signInActionSchema)
  .handler(async ({ input }) => {
    await AuthService.signInWithCredentials({
      email: input.email,
      password: input.password,
      redirect: input.redirect,
      redirectTo: input.redirectTo,
    });
    return null;
  });

const CredentialsSchema = z.object({
  email: z.string().email(),
  password: z.string().min(4),
  redirect: z.boolean().optional(),
  redirectTo: z.string().optional(),
});

type SignInCredentialsInput = z.infer<typeof CredentialsSchema>;

export const signInWithCredentialsAction = async (input: SignInCredentialsInput) => {
  // Validate input using the schema (optional but good practice)
  const parsed = CredentialsSchema.safeParse(input);
  if (!parsed.success) {
    console.error("Invalid input to signInWithCredentialsAction:", parsed.error);
    return { ok: false, error: "Invalid input data" };
  }

  const { email, password, redirect, redirectTo } = parsed.data;

  try {
    const result = await AuthService.signInWithCredentials({
      email,
      password,
      redirect: redirect ?? false, // Use provided redirect, default to false
      redirectTo,
    });

    if (!result.ok) {
      return { ok: false, error: result.error ?? "Unknown sign-in error" };
    }

    return { ok: true, url: result.url };
  } catch (error: any) {
    // Check if it's an AuthError from next-auth
    if (error.type === "CredentialsSignin" || error.code === "CredentialsSignin") {
      return { ok: false, error: STATUS_CODES.CREDENTIALS.message };
    }

    // Known credential errors don't need extra logging
    if (error.message === STATUS_CODES.CREDENTIALS.message) {
      return { ok: false, error: error.message };
    }

    console.error("Error in signInWithCredentialsAction:", error);
    return { ok: false, error: error.message || "Sign in failed" };
  }
};

export const signUpWithCredentialsAction = async (_prevState: ActionState, formData: FormData) => {
  const parsed = CredentialsSchema.safeParse(Object.fromEntries(formData));

  if (!parsed.success) {
    return { ok: false, error: "Invalid form data" };
  }
  try {
    const result = await AuthService.signUpWithCredentials(parsed.data);

    if (!result.ok || !result.user) {
      return { ok: false, error: result.error || "Sign up failed" };
    }

    // Send verification email (moved from auth service for clarity)
    try {
      if (!resend) {
        console.warn("Resend client not initialized - skipping verification email");
      } else {
        const RESEND_FROM_EMAIL = env.RESEND_FROM_EMAIL || "noreply@example.com";
        await resend.emails.send({
          from: RESEND_FROM_EMAIL,
          to: parsed.data.email,
          subject: "Welcome to Our App - Verify Your Email",
          html: `
							<p>Welcome! Your account has been created.</p>
							<p>You can now sign in and start using the app:</p>
							<a href="${BASE_URL}/sign-in">Sign In</a>
						`,
        });
      }
    } catch (emailError) {
      console.error("Failed to send verification email", emailError);
      // Proceed with sign-up even if email fails, but log the error
    }

    return { ok: true, user: result.user }; // Only return necessary info
  } catch (error: any) {
    console.error("Error in signUpWithCredentialsAction:", error);
    return { ok: false, error: error.message || "Sign up failed" };
  }
};

export const signOutAction = async (options?: AuthOptions) => {
  return await AuthService.signOut(options);
};

export const forgotPasswordAction = createServerAction()
  .input(forgotPasswordSchema)
  .handler(async ({ input }) => {
    try {
      await AuthService.forgotPassword(input.email);
      return { ok: true };
    } catch (error) {
      console.error("Error in forgotPasswordAction:", error);
      return {
        ok: false,
        error: error instanceof Error ? error.message : STATUS_CODES.AUTH_ERROR.message,
