import { usePathname, useRouter } from "next/navigation";
import { useSession } from "next-auth/react";
import { useEffect } from "react";
import { BASE_URL } from "@/config/base-url";
import { routes } from "@/config/routes";
import { SEARCH_PARAM_KEYS } from "@/config/search-param-keys";
import { createRedirectUrl } from "@/lib/utils/redirect";

export function useRequireAuth(redirectTo: string = routes.auth.signIn) {
  const { data: session, status } = useSession();
  const router = useRouter();
  const pathname = usePathname();

  useEffect(() => {
    if (status === "loading") return; // Still loading

    if (!session) {
      const url = createRedirectUrl(redirectTo, { nextUrl: pathname ?? "/" });
      router.push(url);
    }
  }, [session, status, router, pathname, redirectTo]);

  return { session, isLoading: status === "loading" };
}

/**
 * Hook to get sign-in redirect URL for the current pathname
 * Only use this in Client Components
 */
export function useSignInRedirectUrl(): string {
  const pathname = usePathname();
  return createRedirectUrl(routes.auth.signIn, { nextUrl: pathname ?? "/" });
}

/**
 * Hook to get sign-out redirect URL for the current pathname
 * Only use this in Client Components
 */
export function useSignOutRedirectUrl(): string {
  const pathname = usePathname();
  return createRedirectUrl(routes.auth.signOut, { nextUrl: pathname ?? "/" });
}

import { usePathname, useRouter } from "next/navigation";
import { useEffect } from "react";
import { routes } from "@/config/routes";
import { STATUS_CODES } from "@/config/status-codes";
import { AuthenticationError } from "@/lib/errors/authentication-error";
import { logger } from "@/lib/logger";
import { redirect } from "@/lib/utils/redirect";

/**
 * A hook that handles redirection after sign-in attempts, particularly for authentication errors
 *
 * @param error - Optional error object that triggered the redirect
 * @returns void
 *
 * @example
 * ```tsx
 * useRedirectAfterSignIn(error);
 * ```
 */

export const useRedirectAfterSignIn = (error?: Error) => {
  const router = useRouter();
  const pathname = usePathname();

  useEffect(() => {
    const redirectToSignIn = () => {
      redirect(routes.auth.signIn, {
        code: STATUS_CODES.AUTH.code,
        nextUrl: pathname ?? undefined,
      });
    };

    if (error instanceof AuthenticationError) {
      logger.info("ErrorBoundary: Authentication error, redirecting to sign in");
      redirectToSignIn();
    }
  }, [error, router, pathname]);
};

import { z } from "zod";

export const signInSchema = z.object({
  email: z
    .string({ required_error: "Email is required" })
    .email("Please enter a valid email address."),
  password: z.string({ required_error: "Password is required" }).min(4, {
    message: "Password must be at least 4 characters.",
  }),
});

export const signInActionSchema = signInSchema.extend({
  redirectTo: z.string().optional(),
  redirect: z.boolean().optional(),
});

export const signUpSchema = signInActionSchema;

export const forgotPasswordSchema = signInSchema.pick({ email: true });

export const resetPasswordSchema = z
  .object({
    token: z.string({ required_error: "Reset token is required." }),
    password: z.string({ required_error: "Password is required" }).min(4, {
      message: "Password must be at least 4 characters.",
    }),
    passwordConfirm: z.string({ required_error: "Please confirm your password." }),
  })
  .refine((data) => data.password === data.passwordConfirm, {
    message: "Passwords do not match.",
    path: ["passwordConfirm"],
  });

import { z } from "zod";
import { REGEX_PATTERNS } from "@/lib/utils/regex-patterns";

export const userSchema = z.object({
  name: z.string().min(1, { message: "Name is required" }),

  email: z.string().email("Please enter a valid email address."),
  password: z.string({ required_error: "Password is required" }).min(6, {
    message: "Password must be at least 6 characters.",
  }),

  location: z.string().min(1, { message: "Enter a valid zip code or location" }),
  phone: z.string().regex(REGEX_PATTERNS.phone, {
    message: "Please enter a valid phone number.",
  }),
  website: z
    .string()
    .regex(REGEX_PATTERNS.url, { message: "Please enter a valid website URL." })
    .optional()
    .or(z.literal("")),

  acceptTerms: z
    .union([z.boolean(), z.string()])
    .refine(
      (value) => {
        if (typeof value === "boolean") {
          return value === true;
        }
        return false;
      },
      {
        message: "You must accept the terms and conditions",
      }
    )
    .transform((value) => {
      if (typeof value === "string") {
        return value === "true" || value === "on";
      }
      return value;
    }),
});

export const userSignUpSchema = userSchema.pick({
  email: true,
  password: true,
});

export const userApplySchema = userSchema
  .pick({
    email: true,
    password: true,
    acceptTerms: true,
  })
  .extend({
    // Optional fields
    name: userSchema.shape.name.optional(),
    location: userSchema.shape.location.optional(),
    phone: userSchema.shape.phone.optional(),
    website: userSchema.shape.website.optional(),
  });

import { AuthError } from "next-auth";
import { STATUS_CODES } from "@/config/status-codes";

/*
Custom Error message for login
@see: https://github.com/nextauthjs/next-auth/issues/9099
*/
export class AuthenticationError extends AuthError {
  constructor(options?: string) {
    super(options);

    if (typeof options === "string") {
      this.message = options;
    } else {
      this.message = STATUS_CODES.AUTH_ERROR.message;
    }
  }
  code = STATUS_CODES.AUTH_ERROR.code;
}

